/* ── Detect OS ── */
function useDetectedOS() {
  const [os, setOs] = useState(null)
  useEffect(() => {
    const ua = navigator.userAgent.toLowerCase()
    if (ua.includes('iphone') || ua.includes('ipad')) setOs('ios')
    else if (ua.includes('android')) setOs('android')
    else if (ua.includes('mac')) setOs('macos')
    else if (ua.includes('linux')) setOs('linux')
    else if (ua.includes('win')) setOs('windows')
    else setOs('windows')
  }, [])
  return os
}

/* ── QR Code Placeholder ── */
function QRCode({ url, size = 140 }) {
  const cells = 11
  const cellSize = size / cells
  const hash = url.split('').reduce((a, c) => ((a << 5) - a + c.charCodeAt(0)) | 0, 0)
  const bits = []
  for (let i = 0; i < cells * cells; i++) {
    const v = ((hash * (i + 1) * 2654435761) >>> 0) % 4
    bits.push(v < 2)
  }
  const setFinder = (r, c) => {
    for (let dr = 0; dr < 3; dr++) for (let dc = 0; dc < 3; dc++) {
      const idx = (r + dr) * cells + (c + dc)
      bits[idx] = dr === 0 || dr === 2 || dc === 0 || dc === 2 || (dr === 1 && dc === 1)
    }
  }
  setFinder(0, 0); setFinder(0, cells - 3); setFinder(cells - 3, 0)
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ borderRadius: 10, background: '#fff' }}>
      {bits.map((on, i) => on ? (
        <rect key={i} x={(i % cells) * cellSize + 2} y={Math.floor(i / cells) * cellSize + 2}
          width={cellSize - 1} height={cellSize - 1} rx={1} fill={T.bg} />
      ) : null)}
    </svg>
  )
}

